using UnityEngine;

public class PlayerController : MonoBehaviour
{
    [Header("Movement")]
    public float moveSpeed = 5f;
    public float jumpForce = 10f;
    public float dashSpeed = 15f;
    public float dashDuration = 0.2f;

    [Header("Ground Check")]
    public Transform groundCheck;
    public float groundCheckRadius = 0.2f;
    public LayerMask groundLayer;

    [Header("References")]
    private Rigidbody2D rb;
    private Animator animator;
    private SpriteRenderer spriteRenderer;

    private bool isGrounded;
    private bool isDashing;
    private bool canMove = true;
    private float dashTimer;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
        animator = GetComponent<Animator>();
        spriteRenderer = GetComponent<SpriteRenderer>();

        if (rb == null)
            Debug.LogError("Rigidbody2D is required!");
        if (animator == null)
            Debug.LogError("Animator is required!");
    }

    void Update()
    {
        if (!canMove) return;

        // Ground check
        isGrounded = Physics2D.OverlapCircle(groundCheck.position, groundCheckRadius, groundLayer);

        // Input
        float horizontal = Input.GetAxis("Horizontal");

        // Flip sprite
        if (horizontal != 0)
        {
            Vector3 scale = transform.localScale;
            scale.x = Mathf.Sign(horizontal) * Mathf.Abs(scale.x);
            transform.localScale = scale;
        }

        // Animation
        animator.SetFloat("Speed", Mathf.Abs(horizontal));
        animator.SetBool("Grounded", isGrounded);

        // Jump
        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
            animator.SetTrigger("Jump");
        }

        // Dash
        if (Input.GetKeyDown(KeyCode.LeftShift) && !isDashing)
        {
            StartDash();
        }

        // Update dash
        if (isDashing)
        {
            dashTimer -= Time.deltaTime;
            if (dashTimer <= 0)
            {
                EndDash();
            }
        }
    }

    void FixedUpdate()
    {
        if (!canMove) return;

        float horizontal = Input.GetAxis("Horizontal");

        if (isDashing)
        {
            rb.velocity = new Vector2(Mathf.Sign(transform.localScale.x) * dashSpeed, 0);
        }
        else
        {
            rb.velocity = new Vector2(horizontal * moveSpeed, rb.velocity.y);
        }
    }

    void StartDash()
    {
        isDashing = true;
        dashTimer = dashDuration;
        animator.SetTrigger("Dash");

        // Make player invulnerable during dash
        gameObject.layer = LayerMask.NameToLayer("Invulnerable");
    }

    void EndDash()
    {
        isDashing = false;
        gameObject.layer = LayerMask.NameToLayer("Player");

        // Small cooldown
        rb.velocity = new Vector2(rb.velocity.x * 0.5f, rb.velocity.y);
    }

    public void SetCanMove(bool canMove)
    {
        this.canMove = canMove;
    }

    public void TakeDamage(int damage)
    {
        if (isDashing) return; // Invulnerable during dash

        animator.SetTrigger("Hit");
        // Health handled by HealthComponent
    }

    void OnDrawGizmosSelected()
    {
        if (groundCheck != null)
        {
            Gizmos.color = Color.green;
            Gizmos.DrawWireSphere(groundCheck.position, groundCheckRadius);
        }
    }
}

