using UnityEngine;

public class PlayerError : MonoBehaviour
{
    void Update()
    {
        // Forgetting Time.deltaTime
        transform.Translate(Vector3.right * 5f);  // Frame-dependent!

        // Using transform on physics object
        rb.velocity = Vector2.right * 5f;  // This is correct for physics
        // But transform.Translate bypasses physics
    }
}

phase2.explanation:
Using `transform.Translate` on a Rigidbody bypasses physics. Use `rb.velocity` instead.

**The fix:**
```csharp
void FixedUpdate()
{
    rb.velocity = new Vector2(horizontal * moveSpeed, rb.velocity.y);
}
```

**Sharp-chan says:**
"Use Rigidbody for physics objects. Use Transform for direct control."
